-- Node: ab-treatment (2 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":6,"title":"Treatment Considerations","body":"**Sodium Bicarbonate:**\n[Sodium Bicarbonate](#/drug/sodium-bicarbonate/metabolic acidosis) — indications, dosing, and evidence.\n\n**Indications for bicarbonate:** [12][17]\n• pH ≤ 7.20 with moderate-to-severe AKI (BICAR-ICU: NNT 6 for 28-day mortality)\n• TCA overdose (sodium channel blockade)\n• Salicylate toxicity (urinary alkalinization)\n• Life-threatening hyperkalemia\n• Bicarbonate-losing conditions (severe diarrhea, RTA)\n\n**Note:** BICAR-ICU enrolled pH ≤ 7.20 + AKIN 2-3. The pH < 6.9 threshold is ADA guidance for DKA specifically.\n\n**NOT recommended:** [3][17]\n• Routine cardiac arrest or CPR\n• Routine DKA (unless pH < 6.9 per ADA)\n• Routine lactic acidosis (no hemodynamic benefit proven)\n\n[Fluid Selection Guide](#/info/ab-fluids-guide) — NS vs balanced crystalloids.","citation":[1,2,3,12,13,17],"next":"ab-disposition","calculatorLinks":[{"id":"anion-gap","label":"Anion Gap"},{"id":"stewart-sig","label":"Stewart SID/SIG"}],"summary":"Bicarb for pH≤7.20 with AKI (BICAR-ICU), TCA OD, salicylate tox, severe hyperK — NOT routine in DKA or lactic acidosis","safetyLevel":"warning"}'::jsonb
WHERE id = 'ab-treatment' AND tree_id = 'acid-base';

