UPDATE decision_nodes SET data = '{"type":"info","module":2,"title":"Mild Croup — Glucocorticoid Only","body":"**Single dose glucocorticoid is standard of care for ALL severities of croup.**\n\n**First-line:**\n• [Dexamethasone](#/drug/dexamethasone) **0.6 mg/kg PO** (max 16 mg) — single dose\n\n**Non-inferior alternatives:**\n• [Dexamethasone](#/drug/dexamethasone) **0.15 mg/kg PO** — lower dose equally effective [3][6]\n• [Prednisolone](#/drug/prednisolone) **1 mg/kg PO** — non-inferior symptom relief, BUT higher re-presentation rate (29% vs 7% with dex) [6]\n\n**If unable to tolerate oral:**\n• [Budesonide](#/drug/budesonide-neb) **2 mg nebulized** — effective alternative [5][9]\n• [Dexamethasone](#/drug/dexamethasone) **0.6 mg/kg IM**\n\n**NNT = 7** to prevent one return visit. Reduces return visits/readmissions by ~50%. Safe single-dose profile.","citation":[1,2,3,5,6,8],"next":"croup-mild-obs","summary":"Dexamethasone 0.6 mg/kg PO single dose for ALL severities — NNT 7 to prevent return visit"}'::jsonb
