-- Node: diarrhea-cdiff-treatment (3 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"result","module":3,"title":"C. difficile Treatment","body":"**Non-severe (first episode):** [IDSA/SHEA 2021]\n• [Fidaxomicin](#/drug/fidaxomicin/c difficile) **200 mg PO BID × 10 days** (PREFERRED — lower recurrence)\n• Alternative: [Vancomycin](#/drug/vancomycin/c difficile) 125 mg PO QID × 10 days\n• Metronidazole only if fidaxomicin/vancomycin unavailable\n\n**Severe (WBC >15K, Cr >1.5):**\n• [Fidaxomicin](#/drug/fidaxomicin/c difficile) 200 mg PO BID × 10 days (preferred)\n• OR [Vancomycin](#/drug/vancomycin/c difficile) 125 mg PO QID × 10 days\n• Do NOT use metronidazole alone for severe disease\n\n**Fulminant (hypotension, ileus, megacolon):**\n• [Vancomycin](#/drug/vancomycin/c difficile) 500 mg PO/NG QID\n• PLUS [Metronidazole](#/drug/metronidazole/c difficile) 500 mg IV q8h\n• Consider rectal vancomycin enema if ileus present\n• **Surgical consult** — colectomy may be lifesaving\n\n**Disposition:** Admit severe and fulminant cases. Non-severe may be discharged with close follow-up.\n\n[Special Populations](#/node/diarrhea-special-pops)","citation":[5,6],"recommendation":"Stop offending antibiotic. Fidaxomicin is preferred first-line (lower recurrence than vancomycin). Admit severe and fulminant cases.","treatment":{"firstLine":{"drug":"Fidaxomicin","dose":"200 mg","route":"PO","frequency":"BID","duration":"10 days","notes":"Preferred per IDSA/SHEA 2021 — lower recurrence rate than vancomycin."},"alternative":{"drug":"Vancomycin","dose":"125 mg","route":"PO","frequency":"QID","duration":"10 days","notes":"Alternative if fidaxomicin unavailable. Increase to 500 mg PO/NG QID for fulminant disease."},"monitoring":"WBC, creatinine, clinical response. Surgical consult for fulminant cases (hypotension, ileus, megacolon)."},"confidence":"definitive","summary":"C. difficile Treatment — determine disposition and follow-up plan based on clinical findings"}'::jsonb
