UPDATE decision_nodes SET data = '{"type":"info","module":3,"title":"Empiric Antibiotics - Age <4 Years","body":"***Kingella kingae* considerations:** [5,9]\n\n*K. kingae* is the **most common pathogen** in children 6 months - 4 years in many regions. [5]\n\n**Characteristics:**\n- Fastidious organism - standard cultures often negative\n- Requires PCR or enriched culture techniques\n- Mild clinical presentation (low-grade fever, modest CRP)\n- Excellent prognosis with appropriate treatment [5,9]\n\n**K. kingae antibiotic sensitivities:**\n- Susceptible to: Beta-lactams, aminoglycosides, fluoroquinolones\n- **Resistant to:** Vancomycin, clindamycin [5,9]\n\n**First-line regimen:**\n[Cefazolin](#/drug/cefazolin/osteomyelitis) 40 mg/kg IV q8h\n- Covers both *K. kingae* AND *S. aureus*\n- Do NOT use clindamycin alone in this age group\n\n**Oral step-down:**\n[Amoxicillin-clavulanate](#/drug/amoxicillin-clavulanate/osteomyelitis) or cephalexin","citation":[5,9],"next":"osteo-surgical-consult","treatment":{"firstLine":{"drug":"Cefazolin","dose":"40 mg/kg","route":"IV","frequency":"q8h","duration":"Until improvement, then oral transition","notes":"Covers Kingella AND S. aureus; do NOT use clindamycin alone <4 years"},"alternative":{"drug":"Amoxicillin-clavulanate","dose":"90 mg/kg/day (amoxicillin component)","route":"PO","frequency":"divided q12h","duration":"Oral step-down option","notes":"Good Kingella coverage; alternative for oral transition"},"monitoring":"Clinical response; CRP trend; consider K. kingae PCR if available"}}'::jsonb
