UPDATE decision_nodes SET data = '{"type":"question","module":1,"title":"Xylazine Toxicity — Initial Assessment","body":"**Xylazine Quick Reference** — key facts at a glance.\n\n**What is Xylazine (\"Tranq\")?**\n• **Alpha-2 adrenergic agonist** (same class as clonidine, dexmedetomidine)\n• FDA-approved for veterinary use ONLY — not approved for humans\n\n**The epidemic (2025 update):**\n• **MEDETOMIDINE now dominant** in some markets — detected in **72% of Philadelphia samples** (Oct-Dec 2024), while xylazine dropped from 98% to 31% [CDC MMWR April 2025]\n• Medetomidine is **10x more potent** than xylazine — expect more severe sedation and bradycardia\n• Same management principles apply (alpha-2 agonist toxidrome)\n\n**Critical point:** These drugs are **NOT reversed by naloxone** — they are not opioids. However, **still give naloxone** because 95% of exposures involve fentanyl co-ingestion [1][2].\n\nWhat is the patient''s current presentation?","citation":[1,2],"options":[{"label":"Acute overdose presentation","description":"Respiratory depression, altered mental status, recent use","next":"xyl-oa2a"},{"label":"Skin wounds present","description":"Necrotic ulcers, non-healing wounds, may or may not be at injection sites","next":"xyl-wound-assess"},{"label":"Withdrawal symptoms","description":"Restless, anxious, tachycardic — recent cessation of use","next":"xyl-withdrawal"}],"calculatorLinks":[{"id":"xyl-wound-staging","label":"Xylazine Wound Staging"},{"id":"xyl-withdrawal-comparison","label":"Tranq vs Opioid Withdrawal"}],"summary":"Alpha-2 agonist NOT reversed by naloxone — medetomidine now 72% of Philly supply (10x more potent than xylazine)","safetyLevel":"critical"}'::jsonb
